import React from 'react';

export const RevenueChart = () => {
  const data = [20, 35, 45, 30, 55, 40, 65];
  const maxValue = Math.max(...data);

  return (
    <div className="flex items-end justify-between h-20 px-2">
      {data.map((value, index) => (
        <div key={index} className="flex flex-col items-center">
          <div
            className="bg-green-500 rounded-t w-6 transition-all duration-300 hover:bg-green-600"
            style={{ height: `${(value / maxValue) * 100}%` }}
          />
          <span className="text-xs text-gray-500 mt-1">{index + 1}</span>
        </div>
      ))}
    </div>
  );
};

export const EnrollmentChart = () => {
  const data = [15, 25, 35, 20, 45, 30, 50];
  const maxValue = Math.max(...data);

  return (
    <div className="flex items-end justify-between h-20 px-2">
      {data.map((value, index) => (
        <div key={index} className="flex flex-col items-center">
          <div
            className="bg-blue-500 rounded-t w-6 transition-all duration-300 hover:bg-blue-600"
            style={{ height: `${(value / maxValue) * 100}%` }}
          />
          <span className="text-xs text-gray-500 mt-1">W{index + 1}</span>
        </div>
      ))}
    </div>
  );
};

export const PerformanceChart = () => {
  const categories = [
    { name: 'Development', percentage: 70, color: 'blue' },
    { name: 'Design', percentage: 45, color: 'green' },
    { name: 'Business', percentage: 60, color: 'yellow' },
    { name: 'AI/Data Science', percentage: 35, color: 'purple' }
  ];

  return (
    <div className="space-y-3">
      {categories.map((category, index) => (
        <div key={index} className="flex justify-between items-center">
          <span className="text-sm font-medium">{category.name}</span>
          <div className="flex items-center space-x-2">
            <div className="w-20 bg-gray-200 rounded-full h-2">
              <div 
                className={`bg-${category.color}-500 h-2 rounded-full transition-all duration-500`}
                style={{ width: `${category.percentage}%` }}
              />
            </div>
            <span className="text-xs text-gray-600 w-8">{category.percentage}%</span>
          </div>
        </div>
      ))}
    </div>
  );
};
